from flask import Flask, request, redirect
from flask_mail import Mail, Message
import os
from flask_sqlalchemy import SQLAlchemy
from itsdangerous import URLSafeSerializer

app = Flask(__name__)

app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
app.config['SECRET_KEY'] = os.urandom(24)
app.config['MAIL_SERVER']='smtp.gmail.com'
app.config['MAIL_PORT'] = 465
app.config['MAIL_USERNAME'] = 'youremail@gmail.com'
app.config['MAIL_PASSWORD'] = 'yourpassword'
app.config['MAIL_USE_TLS'] = False
app.config['MAIL_USE_SSL'] = True

mail = Mail(app)
db = SQLAlchemy(app)

s = URLSafeSerializer(app.config['SECRET_KEY'])

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(80), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)


@app.route("/enable-mfa", methods=['POST'])
def enable_mfa():
    request_data = request.get_json()
    email = request_data.get('email')
    user = User.query.filter_by(email=email).first()
    if not user:
        return {"error": "User not found"}, 404
    user.mfa_enabled = True
    db.session.commit()
    return {"msg": "MFA enabled successfully"}


@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    request_data = request.get_json()
    email = request_data.get('email')
    user = User.query.filter_by(email=email).first()
    if not user:
        return {"error": "User not found"}, 404
    user.mfa_enabled = False
    db.session.commit()
    return {"msg": "MFA disabled successfully"}

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    request_data = request.get_json()
    email = request_data.get('email')
    user = User.query.filter_by(email=email).first()
    if not user:
        return {"error": "User not found"}, 404

    token = s.dumps(user.email, salt='email-confirm')
    msg = Message("Reset MFA",
                  sender="noreply@demo.com",
                  recipients=[user.email])
    link = url_for('confirm_email', token=token, _external=True)
    msg.body = f'Your link is {link}'
    mail.send(msg)
    return {"msg": "Email sent for MFA reset"}

@app.route('/confirm-email/<token>')
def confirm_email(token):
    try:
        email = s.loads(token, salt='email-confirm')
    except:
        return {"error": "Invalid link"}, 404

    user = User.query.filter_by(email=email).first()
    if not user:
        return {"error": "User not found"}, 404
    user.mfa_enabled = False
    db.session.commit()
    return redirect("/login", code=302)